// Classic TR-808 groove – samples load automatically on first play
// Swap RolandTR808 for RolandTR909, RolandTR606, RolandTR707, LinnLM1, OberheimDMX, etc.
stack(
  s("RolandTR808_bd ~ RolandTR808_bd ~").gain(0.95),
  s("~ RolandTR808_sd ~ RolandTR808_sd").gain(0.85),
  s("RolandTR808_hh*8").gain(0.45).pan(sine.slow(4).range(0.3, 0.7)),
  s("~ ~ ~ RolandTR808_oh").gain(0.6),
  s("~ ~ RolandTR808_cp ~").gain(0.5)
).cpm(120)
